public abstract class Actor {
	private Stage stage;
	private Group parent;
	private final DelayedRemovalArray<EventListener> listeners = new DelayedRemovalArray(0);
	private final DelayedRemovalArray<EventListener> captureListeners = new DelayedRemovalArray(0);
	private final DelayedRemovalArray<Actor> captureActors = new DelayedRemovalArray(0);
	private final Array<Action> actions = new Array(0);

	private String name;
	private boolean touchable = true;
	private boolean visible = true;
	private float x, y;
	private float width, height;
	private float originX, originY;
	private float scaleX = 1, scaleY = 1;
	private float rotation;
	private final Color color = new Color(1, 1, 1, 1);

	/** Creates an actor without a name. */
	public Actor () {
		this.name = null;
	}

	public Actor (String name) {
		this.name = name;
	}

	/** Draws the actor. The SpriteBatch is configured to draw in the parent's coordinate system.
	 * {@link SpriteBatch#draw(com.badlogic.gdx.graphics.g2d.TextureRegion, float, float, float, float, float, float, float, float, float)
	 * This draw method} is convenient to draw a rotated and scaled TextureRegion. {@link SpriteBatch#begin()} has already been
	 * called on the SpriteBatch. If {@link SpriteBatch#end()} is called to draw without the SpriteBatch then
	 * {@link SpriteBatch#begin()} must be called before the method returns.
	 * <p>
	 * The default implementation does nothing.
	 * @param parentAlpha Should be multipied with the actor's alpha, allowing a parent's alpha to affect all children. */
	public void draw (SpriteBatch batch, float parentAlpha) {
	}

	/** Updates the actor based on time. Typically this is called each frame by {@link Stage#act(float)}.
	 * <p>
	 * The default implementation does nothing.
	 * @param delta Time in seconds since the last frame. */
	public void act (float delta) {
		for (int i = 0, n = actions.size; i < n; i++) {
			Action action = actions.get(i);
			if (action.act(delta)) {
				actions.removeIndex(i);
				action.setActor(null);
				i--;
				n--;
			}
		}
	}

	/** Sets this actor as the {@link Event#setTargetActor(Actor) target} and propagates the event to this actor and ancestor actors
	 * as necessary. If this actor is not in the stage, false is returned without firing the event.
	 * @return true of the event was {@link Event#handled() handled}. */
	public boolean fire (Event event) {
		event.stage = getStage();
		if (event.stage == null) return false;
		event.setTargetActor(this);

		// Collect ancestors so event propagation is unaffected by hierachy changes.
		Array<Group> ancestors = Pools.obtain(Array.class);
		Group parent = getParent();
		while (parent != null) {
			ancestors.add(parent);
			parent = parent.getParent();
		}

		try {
			// Notify all parent capture listeners, starting at the root. Ancestors may stop an event before children receive it.
			for (int i = ancestors.size - 1; i >= 0; i--) {
				Group currentTarget = ancestors.get(i);
				currentTarget.notify(event, true);
				if (event.isStopped()) return event.isHandled();
			}

			// Notify the target capture listeners.
			notify(event, true);
			if (event.isStopped()) return event.isHandled();

			// Notify the target listeners.
			notify(event, false);
			if (!event.getBubbles()) return event.isHandled();
			if (event.isStopped()) return event.isHandled();

			// Notify all parent listeners, starting at the target. Children may stop an event before ancestors receive it.
			for (int i = 0, n = ancestors.size; i < n; i++) {
				ancestors.get(i).notify(event, false);
				if (event.isStopped()) return event.isHandled();
			}

			return event.isHandled();
		} finally {
			Pools.free(Array.class);
		}
	}

	/** Sets this actors as the {@link Event#getTargetActor() current target} and notifies this actor's listeners of the event.
	 * Event propagation is not performed. The event {@link Event#setTargetActor(Actor) target} must be set.
	 * @param capture If true, the capture listeners will be notified instead of the regular listeners. */
	public void notify (Event event, boolean capture) {
		if (event.getTargetActor() == null) throw new IllegalArgumentException("The event target cannot be null.");

		if (capture) {
			DelayedRemovalArray<EventListener> listeners = captureListeners;
			if (listeners.size == 0) return;

			event.capture = true;

			DelayedRemovalArray<Actor> actors = captureActors;
			listeners.begin();
			for (int i = 0, n = listeners.size; i < n; i++) {
				Actor actor = actors.get(i);
				event.setContextActor(actor != null ? actor : this);
				listeners.get(i).handle(event);
			}
			listeners.end();
		} else {
			DelayedRemovalArray<EventListener> listeners = this.listeners;
			if (listeners.size == 0) return;

			event.setContextActor(this);
			event.capture = false;

			listeners.begin();
			for (int i = 0, n = listeners.size; i < n; i++)
				listeners.get(i).handle(event);
			listeners.end();
		}
	}

	/** Returns this actor if the specified point is within the actor, or null if it is not. The point is specified in the actor's
	 * local coordinate system (0,0 is the bottom left of the actor and width,height is the upper right).
	 * <p>
	 * This method is used by {@link Group} to delegate touch down events. If this method returns null, touch down will not occur.
	 * <p>
	 * The default implementation returns this actor if the point is within this actor's bounds. */
	public Actor hit (float x, float y) {
		return x > 0 && x < width && y > 0 && y < height ? this : null;
	}

	/** Transforms the given point in stage coordinates to the actor's local coordinate system. */
	public void toLocalCoordinates (Vector2 stageCoords) {
		if (parent == null) return;
		parent.toLocalCoordinates(stageCoords);
		Group.toChildCoordinates(this, stageCoords.x, stageCoords.y, stageCoords);
	}

	/** Transforms the given point in stage coordinates to the actor's local coordinate system. The returned object is
	 * {@link Vector2#tmp}, referenecs to it must not be held. */
	public Vector2 toLocalCoordinates (float stageX, float stageY) {
		Vector2 tmp = Vector2.tmp;
		tmp.x = stageX;
		tmp.y = stageY;
		if (parent == null) return tmp;
		parent.toLocalCoordinates(tmp);
		Group.toChildCoordinates(this, tmp.x, tmp.y, tmp);
		return tmp;
	}

	/** Removes this actor from its parent, if it has a parent. */
	public void remove () {
		if (parent != null) parent.removeActor(this);
	}

	public boolean addListener (EventListener listener) {
		if (!listeners.contains(listener, true)) {
			listeners.add(listener);
			return true;
		}
		return false;
	}

	public boolean removeListener (EventListener listener) {
		return listeners.removeValue(listener, true);
	}

	public Array<EventListener> getListeners () {
		return listeners;
	}

	public boolean addCaptureListener (EventListener listener, Actor actor) {
		// Check for capture listener with same actor;
		for (int i = captureListeners.size - 1; i >= 0; i--) {
			if (captureListeners.get(i) != listener) continue;
			if (captureActors.get(i) != actor) continue;
			return false;
		}
		captureListeners.add(listener);
		captureActors.add(actor);
		return true;
	}

	public boolean addCaptureListener (EventListener listener) {
		// Check for capture listener with null actor;
		for (int i = captureListeners.size - 1; i >= 0; i--) {
			if (captureListeners.get(i) != listener) continue;
			if (captureActors.get(i) != null) continue;
			return false;
		}
		captureListeners.add(listener);
		captureActors.add(null);
		return true;
	}

	public boolean removeCaptureListener (EventListener listener) {
		// Remove capture listener with null actor;
		for (int i = captureListeners.size - 1; i >= 0; i--) {
