class EmailSender {

    private String sender;
    private String smtpHost;
    private int smtpPort;

    public EmailSender(String sender, String smtpHost, int smtpPort) {
        this.sender = sender;
        this.smtpHost = smtpHost;
        this.smtpPort = smtpPort;
    }

    public void send(String recipient, String subject, String body) throws Exception {
        java.util.Properties props = new java.util.Properties();
        props.put("mail.smtp.host", smtpHost);
        props.put("mail.smtp.port", "" + smtpPort);
        System.out.println("Sending from " + sender + " to " + recipient
                + " via " + smtpHost + ":" + smtpPort
                + " subject=" + subject + " body=" + body);
    }
}

