      charCounts[EDIFACT_ENCODATION] += 17.0f / 4.0f;
    } else {
      charCounts[EDIFACT_ENCODATION] += 13.0f / 4.0f;
    }

    if (isSpecialB256(c)) {
      charCounts[BASE256_ENCODATION] += 4.0f;
    } else {
      charCounts[BASE256_ENCODATION]++;
    }
