public class ChessBoard {
    public void setupBackRank(int row, Color color)
    {
        for (PieceType type : new PieceType[] {PieceType.ROOK, PieceType.KNIGHT, PieceType.BISHOP, PieceType.QUEEN, PieceType.KING}) {
            placePiece(row, getStartingColumnForPieceType(type, row), new PieceFactory().createPiece(type, color));
        }
    }

    private int getStartingColumnForPieceType(PieceType type, int row)
    {
        switch (type) {
            case ROOK:
                return row == 0 || row == 7 ? 0 : 7;
            case KNIGHT:
                return row == 0 || row == 7 ? 1 : 6;
            case BISHOP:
                return row == 0 || row == 7 ? 2 : 5;
            default:
                return row == 0 || row == 7 ? 3 : 4;
        }
    }
}

class PieceFactory {
    public Piece createPiece(PieceType type, Color color)
    {
        switch (type) {
            case ROOK:
                return new Rook(color);
            case KNIGHT:
                return new Knight(color);
            case BISHOP:
                return new Bishop(color);
            case QUEEN:
                return new Queen(color);
            case KING:
                return new King(color);
            default:
                return null;
        }
    }
}

