            adjustQuality(i, false);

            if (items[i].sellIn < 0) {
                adjustQuality(i, true);
            }

            items[i].sellIn--;
        }
    }

    private void adjustQuality(int index, boolean afterSellDate) {
        if (items[index].name.equals("Aged Brie")) {
            incrementQuality(index);
        } else if (items[index].name.equals("Backstage passes to a TAFKAL80ETC concert")) {
            incrementQuality(index);
            if (items[index].sellIn < 11) {
                incrementQuality(index);
