            if (items[index].sellIn < 6) {
                incrementQuality(index);
            }
        } else {
            decrementQuality(index, afterSellDate);
        }
    }

    private void incrementQuality(int index) {
        if (items[index].quality < 50) {
            items[index].quality++;
        }
    }

    private void decrementQuality(int index, boolean afterSellDate) {
        if (items[index].quality > 0) {
            if (afterSellDate || items[index].name.equals("Aged Brie")) {
