private boolean encodeContents(Intent intent) {
    if (intent == null) {
        return false;
    }

    String type = intent.getStringExtra(Intents.Encode.TYPE);
    if (type == null || type.isEmpty()) {
        return false;
    }

    switch (type) {
        case Contents.Type.TEXT:
            handleText(intent);
            break;
        case Contents.Type.EMAIL:
            handleEmail(intent);
            break;
        case Contents.Type.PHONE:
            handlePhone(intent);
            break;
        case Contents.Type.SMS:
            handleSms(intent);
            break;
        case Contents.Type.CONTACT:
            handleContact(intent);
            break;
        case Contents.Type.LOCATION:
            handleLocation(intent);
            break;
    }

    return mContents != null && mContents.length() > 0;
}

private void handleText(Intent intent) {
    String data = intent.getStringExtra(Intents.Encode.DATA);
    if (data != null && !data.isEmpty()) {
        mContents = data;
        mDisplayContents = data;
        mTitle = mActivity.getString(R.string.contents_text);
    }
}

private void handleEmail(Intent intent) {
    String data = intent.getStringExtra(Intents.Encode.DATA);
    if (data != null && !data.isEmpty()) {
        mContents = "mailto:" + data;
        mDisplayContents = data;
        mTitle = mActivity.getString(R.string.contents_email);
    }
}

private void handlePhone(Intent intent) {
    String data = intent.getStringExtra(Intents.Encode.DATA);
    if (data != null && !data.isEmpty()) {
        mContents = "tel:" + data;
        mDisplayContents = PhoneNumberUtils.formatNumber(data);
        mTitle = mActivity.getString(R.string.contents_phone);
    }
}

private void handleSms(Intent intent) {
    String data = intent.getStringExtra(Intents.Encode.DATA);
    if (data != null && !data.isEmpty()) {
        mContents = "sms:" + data;
        mDisplayContents = PhoneNumberUtils.formatNumber(data);
        mTitle = mActivity.getString(R.string.contents_sms);
    }
}

private void handleContact(Intent intent) {
    Bundle bundle = intent.getBundleExtra(Intents.Encode.DATA);
    if (bundle != null) {
        StringBuilder newContents = new StringBuilder("MECARD:");
        StringBuilder newDisplayContents = new StringBuilder();

        appendIfNotNull(newContents, newDisplayContents, bundle.getString(Contacts.Intents.Insert.NAME), "N", true);

        String address = bundle.getString(Contacts.Intents.Insert.POSTAL);
        if (!address.isEmpty()) {
            newContents.append("ADR:").append(address).append(';');
            newDisplayContents.append('\n').append(address);
        }

        for (String key : Contents.PHONE_KEYS) {
            String phone = bundle.getString(key);
            if (!phone.isEmpty()) {
                newContents.append("TEL:").append(phone).append(';');
                newDisplayContents.append('\n').append(PhoneNumberUtils.formatNumber(phone));
            }
        }

        for (String key : Contents.EMAIL_KEYS) {
            String email = bundle.getString(key);
            if (!email.isEmpty()) {
                newContents.append("EMAIL:").append(email).append(';');
                newDisplayContents.append('\n').append(email);
            }
        }

        if (newDisplayContents.length() > 0) {
            newContents.append(';');
            mContents = newContents.toString();
            mDisplayContents = newDisplayContents.toString();
            mTitle = mActivity.getString(R.string.contents_contact);
        } else {
            mContents = null;
            mDisplayContents = null;
        }
    }
}

private void handleLocation(Intent intent) {
    Bundle bundle = intent.getBundleExtra(Intents.Encode.DATA);
    if (bundle != null) {
        float latitude = bundle.getFloat("LAT", Float.MAX_VALUE);
        float longitude = bundle.getFloat("LONG", Float.MAX_VALUE);
        if (latitude != Float.MAX_VALUE && longitude != Float.MAX_VALUE) {
            mContents = "geo:" + latitude + ',' + longitude;
            mDisplayContents = latitude + "," + longitude;
            mTitle = mActivity.getString(R.string.contents_location);
        }
    }
}

private void appendIfNotNull(StringBuilder newContents, StringBuilder newDisplayContents, String value, String key, boolean addSeparator) {
    if (value != null && !value.isEmpty()) {
        newContents.append(key).append(':').append(value).append(';');
        newDisplayContents.append(value).append('\n');
    } else if (addSeparator) {
        newContents.append(';');
        newDisplayContents.append('\n');
    }
}
