private class ContentProcessor {
  private String type;
  private String title;

  public ContentProcessor(String type, String title) {
    this.type = type;
    this.title = title;
  }

  public void process(Contents contents, Intent intent) {
    String data = intent.getStringExtra(Intents.Encode.DATA);
    if (data == null || data.length() == 0) {
      contents.mContents = null;
      contents.mDisplayContents = null;
      return;
    }
    if (type.equals(Contents.Type.TEXT)) {
      contents.mContents = data;
      contents.mDisplayContents = data;
      contents.mTitle = title;
    } else if (type.equals(Contents.Type.EMAIL)) {
      contents.mContents = "mailto:" + data;
      contents.mDisplayContents = data;
      contents.mTitle = title;
    } else if (type.equals(Contents.Type.PHONE)) {
      contents.mContents = "tel:" + data;
      contents.mDisplayContents = PhoneNumberUtils.formatNumber(data);
      contents.mTitle = title;
    } else if (type.equals(Contents.Type.SMS)) {
      contents.mContents = "sms:" + data;
      contents.mDisplayContents = PhoneNumberUtils.formatNumber(data);
      contents.mTitle = title;
    } else if (type.equals(Contents.Type.CONTACT)) {
      Bundle bundle = intent.getBundleExtra(Intents.Encode.DATA);
      if (bundle == null) {
        contents.mContents = null;
        contents.mDisplayContents = null;
        return;
      }
      StringBuilder newContents = new StringBuilder();
      StringBuilder newDisplayContents = new StringBuilder();
      newContents.append("MECARD:");
      String name = bundle.getString(Contacts.Intents.Insert.NAME);
      if (name != null && name.length() > 0) {
        newContents.append("N:").append(name).append(';');
        newDisplayContents.append(name);
      }
      String address = bundle.getString(Contacts.Intents.Insert.POSTAL);
      if (address != null && address.length() > 0) {
        newContents.append("ADR:").append(address).append(';');
        newDisplayContents.append('\n').append(address);
      }
      for (int x = 0; x < Contents.PHONE_KEYS.length; x++) {
        String phone = bundle.getString(Contents.PHONE_KEYS[x]);
        if (phone != null && phone.length() > 0) {
          newContents.append("TEL:").append(phone).append(';');
          newDisplayContents.append('\n').append(PhoneNumberUtils.formatNumber(phone));
        }
      }
      for (int x = 0; x < Contents.EMAIL_KEYS.length; x++) {
        String email = bundle.getString(Contents.EMAIL_KEYS[x]);
        if (email != null && email.length() > 0) {
          newContents.append("EMAIL:").append(email).append(';');
          newDisplayContents.append('\n').append(email);
        }
      }
      if (newDisplayContents.length() > 0) {
        newContents.append(';');
        contents.mContents = newContents.toString();
        contents.mDisplayContents = newDisplayContents.toString();
        contents.mTitle = title;
      } else {
        contents.mContents = null;
        contents.mDisplayContents = null;
      }
    } else if (type.equals(Contents.Type.LOCATION)) {
      Bundle bundle = intent.getBundleExtra(Intents.Encode.DATA);
      if (bundle == null) {
        contents.mContents = null;
        contents.mDisplayContents = null;
        return;
      }
      float latitude = bundle.getFloat("LAT", Float.MAX_VALUE);
      float longitude = bundle.getFloat("LONG", Float.MAX_VALUE);
      if (latitude == Float.MAX_VALUE || longitude == Float.MAX_VALUE) {
        contents.mContents = null;
        contents.mDisplayContents = null;
        return;
      }
      contents.mContents = "geo:" + latitude + ',' + longitude;
      contents.mDisplayContents = latitude + "," + longitude;
      contents.mTitle = title;
    }
  }
}

