    appendIfNotNull(newContents, newDisplayContents, "ADR", contact::getAddresses, trim, s -> s);
    appendIfNotNull(newContents, newDisplayContents, "TEL", contact::getPhoneNumbers, trim, PhoneNumberUtils::formatNumber);
    appendIfNotNull(newContents, newDisplayContents, "EMAIL", contact::getEmails, trim, s -> s);
