private <T> void appendIfNotNull(StringBuilder newContents, StringBuilder newDisplayContents, String key, Function<AddressBookParsedResult, T[]> getter, Function<T, String> trimFunc, Function<String, String> transformFunc) {
    T[] values = getter.apply(null);
    if (values != null && values.length > 0) {
        for (T value : values) {
            String trimmedValue = trimFunc.apply(value);
            if (trimmedValue != null) {
                newContents.append(key).append(':').append(transformFunc.apply(trimmedValue)).append(';');
                newDisplayContents.append('\n').append(trimmedValue);
            }
        }
    }
}
