private Document parseAndTranslateDocument(File sourceFile, String language) throws Exception {
  DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
  DocumentBuilder builder = factory.newDocumentBuilder();
  Document document = builder.parse(sourceFile);

  Element rootElement = document.getDocumentElement();
  rootElement.normalize();

  Queue<Node> nodes = new LinkedList<>();
  nodes.add(rootElement);

  while (!nodes.isEmpty()) {
    Node node = nodes.poll();
    if (shouldTranslate(node)) {
      nodes.addAll(getChildNodes(node));
    }
    if (node.getNodeType() == Node.TEXT_NODE) {
      String text = node.getTextContent().trim();
      if (!text.isEmpty()) {
        text = StringsResourceTranslator.translateString(text, language);
        node.setTextContent(text);
      }
    }
  }

  return document;
}

private void appendTranslationParagraph(Document document, String translationText) {
  Node translateText = document.createTextNode(translationText);
  Node paragraph = document.createElement("p");
  paragraph.appendChild(translateText);
  Node body = document.getElementsByTagName("body").item(0);
  body.appendChild(paragraph);
}

